import { Injectable } from "@angular/core";
import { EnvService } from "./env.service";
import { HttpClient } from "@angular/common/http";
import { AlertService } from "./alert.service";
import { BehaviorSubject, Observable } from "rxjs";

@Injectable({
  providedIn: "root",
})
export class DatabaseJobsManagementService {
  constructor(
    private env: EnvService,
    private http: HttpClient,
    private alertService: AlertService
  ) {}

  getEligibleDatabaseJobs = (): Observable<DatabaseJob[]> => {
    try {
      return this.http.get<DatabaseJob[]>(
        this.env.API_URL + `api/Settings/GetEligibleDatabaseJobs`
      );
    } catch (error) {
      console.error("Error GetEligibleDatabaseJobs:", error);
      throw error;
    }
  };

  initiateEligibleDatabaseJob = (
    job: InitiateDatabaseJob
  ): Observable<boolean> => {
    try {
      return this.http.post<boolean>(
        this.env.API_URL + `api/Settings/InitiateEligibleDatabaseJob`,
        job
      );
    } catch (error) {
      console.error("Error InitiateEligibleDatabaseJob:", error);
      throw error;
    }
  };

  toggleEligibleDatabaseJob = (job: ToggleDatabaseJob): Observable<boolean> => {
    try {
      console.log(job);
      return this.http.post<boolean>(
        this.env.API_URL + `api/Settings/ToggleEligibleDatabaseJob`,
        job
      );
    } catch (error) {
      console.error("Error ToggleEligibleDatabaseJob:", error);
      let result = new BehaviorSubject<boolean>(false);
      return result;
    }
  };
}
