import { error } from "console";
import { delay, map } from "rxjs/operators";
import { Component, OnDestroy, OnInit } from "@angular/core";
import { DatabaseJobsManagementService } from "src/app/core/services/database-jobs-management.service";

@Component({
  selector: "app-database-jobs-management",
  templateUrl: "./database-jobs-management.page.html",
  styleUrls: ["./database-jobs-management.page.scss"],
})
export class DatabaseJobsManagementPage implements OnInit, OnDestroy {
  jobs: DatabaseJob[] = [];
  intervalId;

  constructor(
    private databaseJobsManagementService: DatabaseJobsManagementService
  ) {}

  ngOnDestroy(): void {
    clearInterval(this.intervalId);
  }

  async ngOnInit() {
    await this.getEligibleDatabaseJobs();
    this.intervalId = setInterval(
      async () => await this.getEligibleDatabaseJobs(),
      60000
    );
  }

  async getEligibleDatabaseJobs() {
    console.log("aaaaaaaaaaaaaaaaaa");
    this.jobs = (
      await this.databaseJobsManagementService
        .getEligibleDatabaseJobs()
        .toPromise()
    ).map((x) => {
      return {
        ...x,
        enabled: x.enabled == 1 ? true : false,
        isRunning: x.isRunning == 1 ? true : false,
      };
    });
  }

  async enabledChanged(job: DatabaseJob) {
    console.log(this.jobs, job, {
      name: job.name,
      enabled: job.enabled ? 1 : 0,
    });
    let result = await this.databaseJobsManagementService
      .toggleEligibleDatabaseJob({
        name: job.name,
        enable: job.enabled ? 1 : 0,
      })
      .toPromise();
    if (result) {
      await this.getEligibleDatabaseJobs();
    }
  }

  async isRunningChanged(job: DatabaseJob) {
    try {
      let result = await this.databaseJobsManagementService
        .initiateEligibleDatabaseJob({
          name: job.name,
          start: job.isRunning ? 1 : 0,
        })
        .toPromise();
    } catch (error) {
      await this.getEligibleDatabaseJobs();
    }
  }
}
